import {
  Accessor,
  Component,
  createEffect,
  createMemo,
  createRoot,
  createSignal,
  For,
  mergeProps,
  on,
  onCleanup,
  onMount,
  Show,
  untrack,
} from 'solid-js';
import { cn } from '@utils/cn';
import { createThrottle } from '@utils/helper';
import type {
  MansoryBreakpoint,
  MansoryItemLayout,
  MansoryProps,
  MansoryResponsive,
  MansoryVirtualOptions,
} from './mansory.types';

const BREAKPOINTS: Record<Exclude<MansoryBreakpoint, 'default'>, number> = {
  sm: 640,
  md: 768,
  lg: 1024,
  xl: 1280,
  '2xl': 1536,
};

const BP_KEYS = ['sm', 'md', 'lg', 'xl', '2xl'] as const;

const DEFAULT_COLUMNS: MansoryResponsive<number> = {
  default: 1,
  sm: 2,
  md: 3,
  lg: 4,
};

const DEFAULT_GAP = 'gap-4';

const GAP_CACHE_MAX = 50;
const gapCache = new Map<string, number>();

function resolveResponsive<T>(config: T | MansoryResponsive<T>, containerWidth: number): T {
  if (typeof config !== 'object' || config === null || Array.isArray(config)) {
    return config as T;
  }

  const map = config as MansoryResponsive<T>;

  for (let i = BP_KEYS.length - 1; i >= 0; i--) {
    const key = BP_KEYS[i];
    if (containerWidth >= BREAKPOINTS[key] && map[key] !== undefined) {
      return map[key] as T;
    }
  }

  return (map.default ?? (typeof config === 'object' ? undefined : config)) as T;
}

function measureGapPx(gapClass: string, container: HTMLElement): number {
  const probe = document.createElement('div');
  probe.className = `ma06 ${gapClass}`;
  probe.style.display = 'grid';
  probe.style.gridTemplateColumns = '1fr 1fr';

  probe.appendChild(document.createElement('div'));
  probe.appendChild(document.createElement('div'));
  container.appendChild(probe);
  const computed = getComputedStyle(probe);
  const gap = parseFloat(computed.columnGap || computed.gap || '0');
  container.removeChild(probe);
  return gap;
}

function measureGapPxCached(gapClass: string, container: HTMLElement): number {
  if (gapCache.has(gapClass)) return gapCache.get(gapClass)!;
  const value = measureGapPx(gapClass, container);

  if (gapCache.size >= GAP_CACHE_MAX) {
    const firstKey = gapCache.keys().next().value;
    if (firstKey !== undefined) gapCache.delete(firstKey);
  }
  gapCache.set(gapClass, value);
  return value;
}

function computeLayout(
  itemHeights: number[],
  columns: number,
  containerWidth: number,
  gapPx: number,
): { layouts: MansoryItemLayout[]; totalHeight: number; sortedByTop: MansoryItemLayout[] } {
  const cols = Math.max(1, columns);
  const totalGap = gapPx * (cols - 1);
  const colWidth = (containerWidth - totalGap) / cols;

  const colHeights = new Array<number>(cols).fill(0);
  const layouts: MansoryItemLayout[] = [];

  const sortedByTop: MansoryItemLayout[] = [];

  for (let i = 0; i < itemHeights.length; i++) {
    let minCol = 0;
    for (let c = 1; c < cols; c++) {
      if (colHeights[c] < colHeights[minCol]) minCol = c;
    }

    const left = minCol * (colWidth + gapPx);
    const top = colHeights[minCol];
    const height = itemHeights[i] ?? 0;

    const item: MansoryItemLayout = { index: i, top, left, width: colWidth, height };
    layouts.push(item);

    let j = sortedByTop.length - 1;
    while (j >= 0 && sortedByTop[j].top > top) j--;
    sortedByTop.splice(j + 1, 0, item);

    colHeights[minCol] = top + height + gapPx;
  }

  let maxH = 0;
  for (let i = 0; i < colHeights.length; i++) {
    if (colHeights[i] > maxH) maxH = colHeights[i];
  }

  return { layouts, totalHeight: maxH > 0 ? maxH - gapPx : 0, sortedByTop };
}

function findFirstVisible(sorted: MansoryItemLayout[], visTop: number): number {
  let lo = 0,
    hi = sorted.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (sorted[mid].top + sorted[mid].height < visTop) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

interface MansoryItemProps {
  index: number;
  getLayoutAccessor: (index: number) => Accessor<MansoryItemLayout | undefined>;
  items: unknown[];
  itemClass?: string;
  children: MansoryProps['children'];
  onRegister: (index: number, el: HTMLDivElement) => void;
  onUnregister: (index: number) => void;
}

const MansoryItem: Component<MansoryItemProps> = props => {
  const itemLayout = props.getLayoutAccessor(props.index);

  const styles = createMemo(() => {
    const l = itemLayout();
    if (!l) return { wrapper: {} as Record<string, string>, child: {} as Record<string, string> };
    const widthPx = `${l.width}px`;
    return {
      wrapper: { width: widthPx, transform: `translate3d(${l.left}px, ${l.top}px, 0)` },
      child: { width: widthPx },
    };
  });

  return (
    <div
      ref={el => {
        props.onRegister(props.index, el);
        onCleanup(function unregisterItem() {
          props.onUnregister(props.index);
        });
      }}
      data-mansory-idx={props.index}
      class={cn('ma03 ma04', props.itemClass)}
      style={styles().wrapper}
    >
      {props.children(props.items[props.index], () => props.index, styles().child)}
    </div>
  );
};

export const Mansory: Component<MansoryProps> = rawProps => {
  const props = mergeProps(
    {
      columns: DEFAULT_COLUMNS,
      gap: DEFAULT_GAP,
      virtual: false as boolean | MansoryVirtualOptions,
      estimateItemHeight: 200,
      loadMoreThreshold: 200,
    },
    rawProps,
  );

  let containerEl!: HTMLDivElement;
  let innerEl!: HTMLDivElement;

  const [containerWidth, setContainerWidth] = createSignal(0);
  const [itemHeights, setItemHeights] = createSignal<number[]>([]);

  const currentColumns = createMemo(() => {
    const resolved = resolveResponsive<number>(props.columns as number, containerWidth());
    return Math.max(1, resolved ?? 1);
  });

  const currentGapClass = createMemo(() => {
    const resolved = resolveResponsive<string>(props.gap as string, containerWidth());
    return resolved ?? 'gap-4';
  });

  const [gapPx, setGapPx] = createSignal(16);

  createEffect(function trackGapClass() {
    const _ = currentGapClass();
    if (containerEl) {
      setGapPx(measureGapPxCached(currentGapClass(), containerEl));
    }
  });

  const layout = createMemo(() =>
    computeLayout(itemHeights(), currentColumns(), containerWidth(), gapPx()),
  );

  const totalHeight = createMemo(() => layout().totalHeight);

  const layoutAccessors = new Map<number, Accessor<MansoryItemLayout | undefined>>();
  const layoutSetters = new Map<number, (v: MansoryItemLayout | undefined) => void>();
  const layoutDisposers = new Map<number, () => void>();

  function getOrCreateLayoutAccessor(index: number): Accessor<MansoryItemLayout | undefined> {
    if (!layoutAccessors.has(index)) {
      createRoot(function layoutSignalRoot(dispose) {
        layoutDisposers.set(index, dispose);
        const initialValue = untrack(() => layout().layouts[index]);
        const [get, set] = createSignal<MansoryItemLayout | undefined>(initialValue, {
          equals: (a, b) => {
            if (a === b) return true;
            if (!a || !b) return false;
            return (
              a.top === b.top && a.left === b.left && a.width === b.width && a.height === b.height
            );
          },
        });
        layoutAccessors.set(index, get);
        layoutSetters.set(index, set);
      });
    }
    return layoutAccessors.get(index)!;
  }

  function disposeLayoutSignal(index: number) {
    layoutDisposers.get(index)?.();
    layoutDisposers.delete(index);
    layoutAccessors.delete(index);
    layoutSetters.delete(index);
  }

  onCleanup(function disposeAllLayoutSignals() {
    for (const dispose of layoutDisposers.values()) dispose();
    layoutDisposers.clear();
    layoutAccessors.clear();
    layoutSetters.clear();
    keyEntryCache.clear();
  });

  createEffect(function syncLayoutSetters() {
    const newLayouts = layout().layouts;

    for (const [index, setter] of layoutSetters) {
      setter(newLayouts[index]);
    }
  });

  const virtualOpts = createMemo<MansoryVirtualOptions | null>(() => {
    const v = props.virtual;
    if (!v) return null;
    if (v === true) return { overscan: 5 };
    return { overscan: v.overscan ?? 5 };
  });

  const isVirtual = createMemo(() => virtualOpts() !== null);

  const [scrollTop, setScrollTop] = createSignal(0);

  let rafId: number | null = null;
  let pendingScrollTop = 0;

  let loadMoreCooldown = false;
  let loadMoreTimer: ReturnType<typeof setTimeout> | null = null;

  const pendingItemChanges = new Map<number, number>();

  const flushItemHeights = createThrottle(function applyItemHeightChanges() {
    if (pendingItemChanges.size === 0) return;
    const snapshot = new Map(pendingItemChanges);
    pendingItemChanges.clear();

    setItemHeights(prev => {
      let hasChange = false;
      for (const [idx, h] of snapshot) {
        if (prev[idx] !== h) {
          hasChange = true;
          break;
        }
      }
      if (!hasChange) return prev;

      const next = [...prev];
      for (const [idx, h] of snapshot) next[idx] = h;
      return next;
    });
  }, 100);

  onCleanup(function cancelFlushItemHeights() {
    flushItemHeights.cancel();
  });

  const itemRO = new ResizeObserver(entries => {
    for (const entry of entries) {
      const el = entry.target as HTMLDivElement;
      const idx = parseInt(el.dataset.mansoryIdx ?? '-1', 10);
      if (idx < 0) continue;

      const h = entry.contentBoxSize?.[0]?.blockSize ?? entry.contentRect.height;
      pendingItemChanges.set(idx, h);
    }

    flushItemHeights();
  });

  onCleanup(function disconnectItemResizeObserver() {
    itemRO.disconnect();
  });

  onMount(() => {
    const applyContainerWidth = createThrottle(function applyContainerWidthChange(width: number) {
      setContainerWidth(width);
    }, 100);

    const containerRO = new ResizeObserver(entries => {
      for (const entry of entries) {
        const width = entry.contentBoxSize?.[0]?.inlineSize ?? entry.contentRect.width;
        applyContainerWidth(width);
      }
    });
    containerRO.observe(containerEl);
    onCleanup(function disconnectContainerResizeObserver() {
      applyContainerWidth.cancel();
      containerRO.disconnect();
    });
  });

  const itemElMap = new Map<number, HTMLDivElement>();

  function registerItem(index: number, el: HTMLDivElement) {
    itemElMap.set(index, el);
    itemRO.observe(el);
  }

  function unregisterItem(index: number) {
    const el = itemElMap.get(index);
    if (el) {
      itemRO.unobserve(el);
      itemElMap.delete(index);
    }
  }

  createEffect(
    on(
      () => props.items.length,
      len => {
        setItemHeights(prev => {
          const prevLen = prev.length;
          if (prevLen === len) return prev;

          if (len > prevLen) {
            const next = [...prev];
            for (let i = prevLen; i < len; i++) next.push(props.estimateItemHeight);
            return next;
          }

          for (let i = len; i < prevLen; i++) {
            disposeLayoutSignal(i);
          }
          return prev.slice(0, len);
        });
      },
    ),
  );

  function checkLoadMore(currentScrollTop: number) {
    if (!props.onLoadMore || loadMoreCooldown) return;
    const { scrollHeight, clientHeight } = containerEl;
    if (currentScrollTop + clientHeight >= scrollHeight - props.loadMoreThreshold) {
      loadMoreCooldown = true;

      if (loadMoreTimer) clearTimeout(loadMoreTimer);
      loadMoreTimer = setTimeout(() => {
        loadMoreCooldown = false;
        loadMoreTimer = null;
      }, 10_000);
      props.onLoadMore();
    }
  }

  createEffect(
    on(
      () => props.items.length,
      () => {
        if (loadMoreTimer) {
          clearTimeout(loadMoreTimer);
          loadMoreTimer = null;
        }
        loadMoreCooldown = false;
      },
    ),
  );

  onCleanup(function clearLoadMoreTimer() {
    if (loadMoreTimer) clearTimeout(loadMoreTimer);
  });

  onCleanup(function cancelPendingRaf() {
    if (rafId !== null) cancelAnimationFrame(rafId);
  });

  function handleScroll() {
    pendingScrollTop = containerEl.scrollTop;

    if (rafId === null) {
      rafId = requestAnimationFrame(() => {
        rafId = null;
        setScrollTop(pendingScrollTop);
        checkLoadMore(pendingScrollTop);
      });
    }
  }

  const allIndices = createMemo<number[]>((prev = []) => {
    const len = props.items.length;
    if (len === prev.length) return prev;
    if (len > prev.length) {
      const next = [...prev];
      for (let i = prev.length; i < len; i++) next.push(i);
      return next;
    }
    return prev.slice(0, len);
  });

  const renderedIndices = createMemo(() => {
    if (!isVirtual()) {
      return allIndices();
    }

    if (containerWidth() === 0) return [];

    const currentScrollTop = scrollTop();
    const viewportHeight = containerEl.clientHeight;
    const overscan = virtualOpts()?.overscan ?? 5;
    const overscanPx = overscan * props.estimateItemHeight;
    const visTop = currentScrollTop - overscanPx;
    const visBottom = currentScrollTop + viewportHeight + overscanPx;

    const sorted = layout().sortedByTop;
    const start = findFirstVisible(sorted, visTop);
    const indices: number[] = [];
    for (let i = start; i < sorted.length; i++) {
      if (sorted[i].top > visBottom) break;
      indices.push(sorted[i].index);
    }
    return indices;
  });

  const keyEntryCache = new Map<string | number, { key: string | number; index: number }>();

  const renderedKeys = createMemo(() => {
    const indices = renderedIndices();
    if (!props.getItemKey) return indices;

    const activeKeys = new Set<string | number>();

    const entries = indices.map(i => {
      const key = props.getItemKey!(props.items[i], i);
      activeKeys.add(key);

      let entry = keyEntryCache.get(key);
      if (!entry) {
        entry = { key, index: i };
        keyEntryCache.set(key, entry);
      } else {
        entry.index = i;
      }
      return entry;
    });

    for (const k of keyEntryCache.keys()) {
      if (!activeKeys.has(k)) keyEntryCache.delete(k);
    }

    return entries;
  });

  return (
    <div
      ref={containerEl}
      class={cn('ma01', isVirtual() && 'ma05', props.class)}
      onScroll={isVirtual() || props.onLoadMore ? handleScroll : undefined}
    >
      <div ref={innerEl} class="ma02" style={{ height: `${totalHeight()}px` }}>
        <For each={renderedKeys()}>
          {entry => {
            const index = typeof entry === 'number' ? entry : entry.index;
            return (
              <MansoryItem
                index={index}
                getLayoutAccessor={getOrCreateLayoutAccessor}
                items={props.items}
                itemClass={props.itemClass}
                onRegister={registerItem}
                onUnregister={unregisterItem}
              >
                {props.children}
              </MansoryItem>
            );
          }}
        </For>
      </div>

      <Show when={props.items.length === 0}>
        <div class="ma08">No items</div>
      </Show>
    </div>
  );
};
